-// maxInt returns the larger of two integers
-func maxInt(a, b int) int {
-	if a > b {
-		return a
-	}
-	return b
-}
-
-// maxIntPtr returns a pointer to the larger of two *int values
-// Treats nil as 0 for comparison purposes
-func maxIntPtr(a, b *int) *int {
-	aVal := 0
-	bVal := 0
-	if a != nil {
-		aVal = *a
-	}
-	if b != nil {
-		bVal = *b
-	}
-	if aVal >= bVal {
-		return a
-	}
-	return b
-}
