-	var result []string
-
-	// Add all local labels
-	for _, label := range local {
-		if !seen[label] {
-			seen[label] = true
-			result = append(result, label)
-		}
-	}
-
-	// Add remote labels not in local
-	for _, label := range remote {
-		if !seen[label] {
-			seen[label] = true
-			result = append(result, label)
-		}
-	}
-
-	// Sort for deterministic output
-	sort.Strings(result)
