-func issueEqual(a, b *beads.Issue) bool {
-	if a == nil || b == nil {
-		return a == nil && b == nil
-	}
-
-	// Core identification
-	if a.ID != b.ID {
-		return false
-	}
-
-	// Issue content
-	if a.Title != b.Title ||
-		a.Description != b.Description ||
-		a.Design != b.Design ||
-		a.AcceptanceCriteria != b.AcceptanceCriteria ||
-		a.Notes != b.Notes {
