-	}
-
-	// Status & workflow
-	if a.Status != b.Status ||
-		a.Priority != b.Priority ||
-		a.IssueType != b.IssueType {
-		return false
-	}
-
-	// Assignment
-	if a.Assignee != b.Assignee {
